import * as THREE from 'three'

// 莫比乌斯带
function mobius(u, v, target) {
  u = u * Math.PI * 2
  v = v * 2 - 1

  const t = u / 2
  const a = 0.5

  target.x = Math.cos(t) * (a + v * Math.cos(t / 2) * a)
  target.y = Math.sin(t) * (a + v * Math.cos(t / 2) * a)
  target.z = v * Math.sin(t / 2) * a
}

// 克莱因瓶
function klein(u, v, target) {
  u = u * Math.PI * 2
  v = v * Math.PI * 2

  let x, y, z

  if (u < Math.PI) {
    x = 6 * Math.cos(u) * (1 + Math.sin(u)) + (4 * (1 - Math.cos(u) / 2)) * Math.cos(u) * Math.cos(v)
    y = 16 * Math.sin(u) + (4 * (1 - Math.cos(u) / 2)) * Math.sin(u) * Math.cos(v)
    z = (4 * (1 - Math.cos(u) / 2)) * Math.sin(v)
  } else {
    x = 6 * Math.cos(u) * (1 + Math.sin(u)) - (4 * (1 - Math.cos(u) / 2)) * Math.cos(v)
    y = 16 * Math.sin(u)
    z = (4 * (1 - Math.cos(u) / 2)) * Math.sin(v)
  }

  target.set(x, y, z)
  target.multiplyScalar(0.1)
}

