import * as THREE from 'three'
import { EffectComposer } from 'three/addons/postprocessing/EffectComposer.js'
import { RenderPass } from 'three/addons/postprocessing/RenderPass.js'
import { UnrealBloomPass } from 'three/addons/postprocessing/UnrealBloomPass.js'

// 创建Composer
const composer = new EffectComposer(renderer)

// 渲染通道
const renderPass = new RenderPass(scene, camera)
composer.addPass(renderPass)

// 泛光通道
const bloomPass = new UnrealBloomPass(
  new THREE.Vector2(window.innerWidth, window.innerHeight),
  1.5,   // strength
  0.4,   // radius
  0.85   // threshold
)
composer.addPass(bloomPass)

// 创建发光物体
const glowMaterial = new THREE.MeshBasicMaterial({ color: 0x00ffff })
const sphere = new THREE.Mesh(
  new THREE.SphereGeometry(1, 32, 32),
  glowMaterial
)
scene.add(sphere)

// 多个发光点
const lights = []
for (let i = 0; i < 20; i++) {
  const light = new THREE.PointLight(
    new THREE.Color().setHSL(Math.random(), 1, 0.5),
    2,
    10
  )
  light.position.set(
    (Math.random() - 0.5) * 20,
    (Math.random() - 0.5) * 20,
    (Math.random() - 0.5) * 20
  )

  const bulbGeometry = new THREE.SphereGeometry(0.2, 16, 16)
  const bulbMaterial = new THREE.MeshBasicMaterial({ 
    color: light.color 
  })
  const bulb = new THREE.Mesh(bulbGeometry, bulbMaterial)
  light.add(bulb)

  scene.add(light)
  lights.push(light)
}

// 动画循环
function animate() {
  requestAnimationFrame(animate)

  const time = Date.now() * 0.001
  lights.forEach((light, i) => {
    light.position.x = Math.sin(time + i) * 5
    light.position.y = Math.cos(time * 0.7 + i) * 5
    light.position.z = Math.sin(time * 1.3 + i) * 5
  })

  composer.render()
}

animate()

import * as THREE from 'three'
import * as CANNON from 'cannon-es'

// 创建物理世界
const world = new CANNON.World()
world.gravity.set(0, -9.82, 0)
world.broadphase = new CANNON.NaiveBroadphase()

// 地面
const groundShape = new CANNON.Plane()
const groundBody = new CANNON.Body({ mass: 0 })
groundBody.addShape(groundShape)
groundBody.quaternion.setFromEulerAngles(-Math.PI / 2, 0, 0)
world.addBody(groundBody)

// 地面视觉
const groundGeometry = new THREE.PlaneGeometry(20, 20)
const groundMaterial = new THREE.MeshStandardMaterial({ color: 0x808080 })
const groundMesh = new THREE.Mesh(groundGeometry, groundMaterial)
groundMesh.rotation.x = -Math.PI / 2
groundMesh.receiveShadow = true
scene.add(groundMesh)

// 物体列表
const objects = []

// 创建下落的盒子
function createBox() {
  const shape = new CANNON.Box(new CANNON.Vec3(0.5, 0.5, 0.5))
  const body = new CANNON.Body({ mass: 1 })
  body.addShape(shape)
  body.position.set(
    (Math.random() - 0.5) * 10,
    5 + Math.random() * 5,
    (Math.random() - 0.5) * 10
  )
  world.addBody(body)

  const geometry = new THREE.BoxGeometry(1, 1, 1)
  const material = new THREE.MeshStandardMaterial({ 
    color: Math.random() * 0xffffff 
  })
  const mesh = new THREE.Mesh(geometry, material)
  mesh.castShadow = true
  mesh.receiveShadow = true
  scene.add(mesh)

  objects.push({ body, mesh })
}

// 创建下落的球体
function createSphere() {
  const radius = 0.5
  const shape = new CANNON.Sphere(radius)
  const body = new CANNON.Body({ mass: 1 })
  body.addShape(shape)
  body.position.set(
    (Math.random() - 0.5) * 10,
    5 + Math.random() * 5,
    (Math.random() - 0.5) * 10
  )
  world.addBody(body)

  const geometry = new THREE.SphereGeometry(radius, 32, 32)
  const material = new THREE.MeshStandardMaterial({ 
    color: Math.random() * 0xffffff 
  })
  const mesh = new THREE.Mesh(geometry, material)
  mesh.castShadow = true
  mesh.receiveShadow = true
  scene.add(mesh)

  objects.push({ body, mesh })
}

// 定时创建物体
setInterval(() => {
  if (objects.length < 50) {
    Math.random() > 0.5 ? createBox() : createSphere()
  }
}, 500)

// 物理更新
const clock = new THREE.Clock()
function animate() {
  requestAnimationFrame(animate)

  const delta = Math.min(clock.getDelta(), 0.1)
  world.step(1 / 60, delta, 3)

  objects.forEach(({ body, mesh }) => {
    mesh.position.copy(body.position)
    mesh.quaternion.copy(body.quaternion)
  })

  renderer.render(scene, camera)
}

animate()

import * as THREE from 'three'

const particleCount = 10000
const geometry = new THREE.BufferGeometry()
const positions = new Float32Array(particleCount * 3)
const colors = new Float32Array(particleCount * 3)
const sizes = new Float32Array(particleCount)

const color = new THREE.Color()

for (let i = 0; i < particleCount; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 20
  positions[i * 3 + 1] = (Math.random() - 0.5) * 20
  positions[i * 3 + 2] = (Math.random() - 0.5) * 20

  color.setHSL(Math.random(), 1, 0.5)
  colors[i * 3] = color.r
  colors[i * 3 + 1] = color.g
  colors[i * 3 + 2] = color.b

  sizes[i] = Math.random() * 2
}

geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3))
geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3))
geometry.setAttribute('size', new THREE.BufferAttribute(sizes, 1))

const material = new THREE.PointsMaterial({
  size: 0.1,
  vertexColors: true,
  sizeAttenuation: true,
  transparent: true,
  opacity: 0.8,
  blending: THREE.AdditiveBlending
})

const particles = new THREE.Points(geometry, material)
scene.add(particles)

// 动画
function animate() {
  requestAnimationFrame(animate)

  const positions = particles.geometry.attributes.position.array
  const time = Date.now() * 0.001

  for (let i = 0; i < particleCount; i++) {
    positions[i * 3 + 1] += 0.01

    if (positions[i * 3 + 1] > 10) {
      positions[i * 3 + 1] = -10
    }
  }

  particles.geometry.attributes.position.needsUpdate = true
  particles.rotation.y = time * 0.05

  renderer.render(scene, camera)
}

