import * as THREE from 'three'

class FireSystem {
  constructor(scene, count = 5000) {
    this.scene = scene
    this.count = count
    this.particles = []
    this.init()
  }

  init() {
    const geometry = new THREE.BufferGeometry()
    const positions = new Float32Array(this.count * 3)
    const colors = new Float32Array(this.count * 3)
    const sizes = new Float32Array(this.count)
    const velocities = []
    const lives = []

    this.color = new THREE.Color()

    for (let i = 0; i < this.count; i++) {
      this.resetParticle(i, positions, velocities, lives, sizes)
    }

    geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3))
    geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3))
    geometry.setAttribute('size', new THREE.BufferAttribute(sizes, 1))

    const texture = this.createFireTexture()

    this.material = new THREE.PointsMaterial({
      size: 0.3,
      vertexColors: true,
      sizeAttenuation: true,
      transparent: true,
      opacity: 1,
      blending: THREE.AdditiveBlending,
      map: texture,
      depthWrite: false
    })

    this.points = new THREE.Points(geometry, this.material)
    this.scene.add(this.points)

    this.positions = positions
    this.velocities = velocities
    this.lives = lives
    this.sizes = sizes
    this.maxLives = Array(this.count).fill(1)
  }

  createFireTexture() {
    const canvas = document.createElement('canvas')
    canvas.width = 128
    canvas.height = 128
    const ctx = canvas.getContext('2d')

    const gradient = ctx.createRadialGradient(64, 64, 0, 64, 64, 64)
    gradient.addColorStop(0, 'rgba(255, 255, 255, 1)')
    gradient.addColorStop(0.2, 'rgba(255, 200, 50, 1)')
    gradient.addColorStop(0.5, 'rgba(255, 100, 0, 0.8)')
    gradient.addColorStop(1, 'rgba(255, 50, 0, 0)')

    ctx.fillStyle = gradient
    ctx.fillRect(0, 0, 128, 128)

    const texture = new THREE.CanvasTexture(canvas)
    texture.needsUpdate = true
    return texture
  }

  resetParticle(i, positions, velocities, lives, sizes) {
    const radius = Math.random() * 0.5
    const angle = Math.random() * Math.PI * 2

    positions[i * 3] = Math.cos(angle) * radius
    positions[i * 3 + 1] = 0
    positions[i * 3 + 2] = Math.sin(angle) * radius

    velocities[i] = {
      x: (Math.random() - 0.5) * 0.1,
      y: Math.random() * 0.2 + 0.1,
      z: (Math.random() - 0.5) * 0.1
    }

    lives[i] = Math.random() * 0.5 + 0.5
    this.maxLives[i] = lives[i]
    sizes[i] = Math.random() * 0.5 + 0.2
  }

  update(delta) {
    const positions = this.positions
    const colors = this.points.geometry.attributes.color.array
    const sizes = this.points.geometry.attributes.size.array

    for (let i = 0; i < this.count; i++) {
      this.lives[i] -= delta * 0.5

      if (this.lives[i] <= 0) {
        this.resetParticle(i, positions, this.velocities, this.lives, sizes)
        continue
      }

      positions[i * 3] += this.velocities[i].x
      positions[i * 3 + 1] += this.velocities[i].y
      positions[i * 3 + 2] += this.velocities[i].z

      this.velocities[i].x += (Math.random() - 0.5) * 0.01
      this.velocities[i].z += (Math.random() - 0.5) * 0.01

      const lifeRatio = this.lives[i] / this.maxLives[i]

      if (lifeRatio > 0.7) {
        this.color.setRGB(1, 1, 0.5)
      } else if (lifeRatio > 0.3) {
        this.color.setRGB(1, 0.5 + lifeRatio * 0.5, 0)
      } else {
        this.color.setRGB(1, lifeRatio, 0)
      }

      colors[i * 3] = this.color.r
      colors[i * 3 + 1] = this.color.g
      colors[i * 3 + 2] = this.color.b

      sizes[i] = this.sizes[i] * lifeRatio
    }

    this.points.geometry.attributes.position.needsUpdate = true
    this.points.geometry.attributes.color.needsUpdate = true
    this.points.geometry.attributes.size.needsUpdate = true
  }
}

const fireSystem = new FireSystem(scene, 10000)

const clock = new THREE.Clock()
function animate() {
  requestAnimationFrame(animate)
  const delta = clock.getDelta()
  fireSystem.update(delta)
  renderer.render(scene, camera)
}

animate()

